public class FinalVariable {
    public static void main(String[] args) {
        final int MAX_RETRIES = 3;
        final double TAX_RATE = 0.18;
        final String APP_NAME = "BeaCoder";

        System.out.println("App: " + APP_NAME);
        System.out.println("Max retries: " + MAX_RETRIES);

        double price = 500.0;
        double tax = price * TAX_RATE;
        System.out.println("Price: " + price);
        System.out.println("Tax (18%): " + tax);
        System.out.println("Total: " + (price + tax));
    }
}

class Account {
    String owner;

    Account(String owner) { this.owner = owner; }

    // This method is final — subclasses cannot override it
    final String getAccountType() {
        return "Generic Account";
    }

    void displayInfo() {
        System.out.println("Owner: " + owner + " | Type: " + getAccountType());
    }
}

class SavingsAccount extends Account {
    double interestRate;

    SavingsAccount(String owner, double interestRate) {
        super(owner);
        this.interestRate = interestRate;
    }

    // Do NOT attempt to override getAccountType() here

    void showRate() {
        System.out.println("Interest Rate: " + interestRate + "%");
    }
}

public class FinalMethod {
    public static void main(String[] args) {
        Account a = new Account("Alice");
        SavingsAccount s = new SavingsAccount("Bob", 4.5);

        a.displayInfo();
        s.displayInfo();
        s.showRate();
    }
}

final class Utility {
    public static int square(int n) {
        return n * n;
    }

    public static boolean isPalindrome(String s) {
        String reversed = new StringBuilder(s).reverse().toString();
        return s.equals(reversed);
    }
}

// Attempting to extend a final class would cause: "cannot inherit from final Utility"
// class ExtendedUtility extends Utility { } // <-- would NOT compile

public class FinalClass {
    public static void main(String[] args) {
        System.out.println("Square of 9: " + Utility.square(9));
        System.out.println("Is 'racecar' a palindrome? " + Utility.isPalindrome("racecar"));
        System.out.println("Is 'hello' a palindrome? " + Utility.isPalindrome("hello"));
    }
}
